const calc=document.querySelector("[data-calculator]");if(calc){const n=new Intl.NumberFormat("ru-RU"),e={hours:calc.elements.hours,days:calc.elements.days,rate:calc.elements.rate},t={hours:calc.querySelector('[data-output="hours"]'),days:calc.querySelector('[data-output="days"]'),rate:calc.querySelector('[data-output="rate"]'),result:calc.querySelector("[data-result]")},s=()=>{const s=Number(e.hours.value),o=Number(e.days.value),i=Number(e.rate.value);t.hours.textContent=s,t.days.textContent=o,t.rate.textContent=`${n.format(i)} ₽`,t.result.textContent=`${n.format(s*o*i)} ₽`};Object.values(e).forEach(e=>e.addEventListener("input",s)),s()}const header=document.querySelector("[data-header]");if(header){const e=()=>{header.classList.toggle("is-scrolled",window.scrollY>8)};window.addEventListener("scroll",e,{passive:!0}),e()}